s_public\&quot;&gt;&lt;strong&gt;is_public&lt;/strong&gt;&lt;/a&gt;: false&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#\&quot;&gt;&lt;strong&gt;is_system&lt;/strong&gt;&lt;/a&gt;: true&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#metadata_view\&quot;&gt;&lt;strong&gt;metadata_view&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#short_name\&quot;&gt;&lt;strong&gt;short_name&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#is_firehose\&quot;&gt;is_firehose&lt;/a&gt;:&lt;/p&gt; 
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param obPv600CreateCustomViewManagementRequest Request body
     * @return ApiResponse<OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead?>
     * @throws IllegalStateException If the request is not correctly configured
     * @throws IOException Rethrows the OkHttp execute method exception
     */
    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class)
    fun oBPv600CreateCustomViewManagementWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String, obPv600CreateCustomViewManagementRequest: OBPv600CreateCustomViewManagementRequest) : ApiResponse<OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead?> {
        val localVariableConfig = oBPv600CreateCustomViewManagementRequestConfig(bankid = bankid, accountid = accountid, obPv600CreateCustomViewManagementRequest = obPv600CreateCustomViewManagementRequest)

        return request<OBPv600CreateCustomViewManagementRequest, OBPv510CreateUserWithAccountAccessById200ResponsePropertiesHead>(
            localVariableConfig
        )
    }

    /**
     * To obtain the request config of the operation oBPv600CreateCustomViewManagement
     *
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param obPv600CreateCustomViewManagementRequest Request body
     * @return RequestConfig
     */
    fun oBPv600CreateCustomViewManagementRequestConfig(bankid: kotlin.String, accountid: kotlin.String, obPv600CreateCustomViewManagementRequest: OBPv600CreateCustomViewManagementRequest) : RequestConfig<OBPv600CreateCustomViewManagementRequest> {
        val localVariableBody = obPv600CreateCustomViewManagementRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.POST,
            path = "/obp/v6.0.0/management/banks/{bankid}/accounts/{accountid}/views".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }

    /**
